con:mockOperation.con:dispatchPath:
mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation, log)

//Läs in mockens data.xml
import se.skl.rivta.tksupport.soapui.datasource.XmlDataReaderMock
import com.eviware.soapui.support.GroovyUtils
def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/mockdata.xml")
def source = new XmlDataReaderMock(context, dataFile)
source.load()

log.info "Validating Update request..."
context.message = mh.getSchemaErrorsInRequest() ?: getSchematronErrorMessage() ?: mh.getEmptyElementsInRequest() ?: null
if (context.message) {
	return "Error"
}

def records = parseTransactions()
context.message = getDuplicationErrorMessage(records)
logTransactionRecords(records)

log.info context.message ?: "Validation OK"
if (context.message) {
	return "Error"
}else if (mockRequest.requestHeaders['x-mock-response'] != null){
	return mockRequest.requestHeaders['x-mock-response'][0]
}else{
	return mockOperation.getMockResponseByName(context.response) ? context.response : "OK"
}

def getSchematronErrorMessage() {
	log.info "Schematron validation started"
	def groovyUtils = new com.eviware.soapui.support.GroovyUtils(context)
	def schematronFilesFolder = new File(groovyUtils.projectPath + "/schematron")
	def errors = []
	schematronFilesFolder.eachFile { file ->
		log.info "Checking constraints in " + file.name
		errors.add(mh.getSchematronErrorsInRequest(file))
	}
     return errors.findAll().join(" \n")
}

def parseTransactions() {
	def records = []
	def transactions = new XmlSlurper().parseText(mockRequest.getRequestContent()).Body.Update.children()
	transactions.each {
		def keyParts = [ it.engagement.registeredResidentIdentification,
		                 it.engagement.serviceDomain,
		                 it.engagement.categorization,
		                 it.engagement.logicalAddress,
		                 it.engagement.businessObjectInstanceIdentifier,
		                 it.engagement.clinicalProcessInterestId,
		                 it.engagement.sourceSystem,
		                 it.engagement.dataController ]	
		def record = [ 'deleteFlag': it.deleteFlag,
		               'mostRecentContent': it.engagement.mostRecentContent,
		               'uniqueKey': "{" + keyParts.join(";") + "}" ]
		records.add(record)
	}
	return records
}

def getDuplicationErrorMessage(records) {
	log.info "Unique Key validation started"
	def duplicates = records.findAll{r1 -> records.count{r2 -> r1.uniqueKey == r2.uniqueKey} > 1}.unique{it.uniqueKey}

	return duplicates.size() > 0 ? "DUPLICATION ERRORS: The following key values were not unique: " + duplicates.collect(){ '\n' + it.uniqueKey } : null
}

def logTransactionRecords(records) {
	log.info "Received transaction records:"
	log.info "{registeredResidentIdentification;serviceDomain;categorization;logicalAddress;businessObjectInstanceIdentifier;clinicalProcessInterestId;sourceSystem;dataController}\tmostRecentContent\tdeleteFlag"
	records.each {
		def logEntry = [it.uniqueKey, it.mostRecentContent, it.deleteFlag].join("\t")
		log.info logEntry
	}
}
